import React, { useRef, useEffect, useState, useCallback } from 'react';
import './CameraView.css';

const WS_BASE = `ws://${window.location.hostname}:8000`;
const FRAME_INTERVAL_MS = 80; // ~12 FPS

export default function CameraView({ camera }) {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const wsRef = useRef(null);
  const timerRef = useRef(null);
  const [faces, setFaces] = useState([]);
  const [frameDim, setFrameDim] = useState({ w: 1280, h: 720 });
  const [isConnected, setIsConnected] = useState(false);
  const [stats, setStats] = useState({ detected: 0, known: 0, unknown: 0 });

  // Start webcam
  useEffect(() => {
    (async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 1280, height: 720 } });
        if (videoRef.current) videoRef.current.srcObject = stream;
      } catch (e) {
        console.error('Camera access error:', e);
      }
    })();
    return () => {
      videoRef.current?.srcObject?.getTracks().forEach(t => t.stop());
    };
  }, []);

  // WebSocket
  useEffect(() => {
    const connect = () => {
      const ws = new WebSocket(`${WS_BASE}/ws/camera/${camera.camera_id}/`);
      wsRef.current = ws;

      ws.onopen = () => {
        setIsConnected(true);
        startSending();
      };

      ws.onmessage = (e) => {
        const data = JSON.parse(e.data);
        if (data.type === 'face_results') {
          setFaces(data.faces || []);
          setFrameDim({ w: data.frame_width || 1280, h: data.frame_height || 720 });
          setStats({
            detected: data.faces.length,
            known: data.faces.filter(f => !f.is_unknown).length,
            unknown: data.faces.filter(f => f.is_unknown).length,
          });
        }
      };

      ws.onclose = () => {
        setIsConnected(false);
        stopSending();
        setTimeout(connect, 2000);
      };
      ws.onerror = () => ws.close();
    };

    connect();
    return () => {
      stopSending();
      wsRef.current?.close();
    };
  }, [camera.camera_id]);

  const startSending = () => {
    timerRef.current = setInterval(sendFrame, FRAME_INTERVAL_MS);
  };
  const stopSending = () => clearInterval(timerRef.current);

  const sendFrame = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas || !wsRef.current) return;
    if (wsRef.current.readyState !== WebSocket.OPEN) return;
    if (!video.videoWidth) return;

    const ctx = canvas.getContext('2d');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.drawImage(video, 0, 0);

    canvas.toBlob(blob => {
      blob?.arrayBuffer().then(buf => {
        if (wsRef.current?.readyState === WebSocket.OPEN) wsRef.current.send(buf);
      });
    }, 'image/jpeg', 0.75);
  }, []);

  return (
    <div className="cam-card">
      {/* Header */}
      <div className="cam-header">
        <div className="cam-info">
          <span className="cam-name">{camera.name}</span>
          <span className="cam-location">📍 {camera.location}</span>
        </div>
        <div className="cam-status">
          <span className={`live-dot ${isConnected ? 'live' : ''}`} />
          <span>{isConnected ? 'LIVE' : 'Connecting...'}</span>
        </div>
      </div>

      {/* Stats row */}
      <div className="cam-stats">
        <span>👤 {stats.detected} detected</span>
        <span style={{ color: '#10b981' }}>✅ {stats.known} known</span>
        <span style={{ color: '#ef4444' }}>❓ {stats.unknown} unknown</span>
      </div>

      {/* Video + overlay */}
      <div className="cam-video-wrap">
        <video ref={videoRef} autoPlay muted playsInline className="cam-video" />
        <div className="cam-overlay">
          {faces.map((face, i) => (
            <FaceBox key={i} face={face} fw={frameDim.w} fh={frameDim.h} />
          ))}
        </div>
        <canvas ref={canvasRef} style={{ display: 'none' }} />
      </div>
    </div>
  );
}

function FaceBox({ face, fw, fh }) {
  const [x1, y1, x2, y2] = face.bbox;
  const left   = `${(x1 / fw) * 100}%`;
  const top    = `${(y1 / fh) * 100}%`;
  const width  = `${((x2 - x1) / fw) * 100}%`;
  const height = `${((y2 - y1) / fh) * 100}%`;
  const color  = face.is_unknown ? '#ef4444' : '#10b981';

  return (
    <div className="face-box" style={{ left, top, width, height, borderColor: color }}>
      <div className="face-label" style={{ background: face.is_unknown ? '#ef4444cc' : '#10b981cc' }}>
        <div className="face-name">{face.label}</div>
        {face.label_kh && <div className="face-name-kh">{face.label_kh}</div>}
        {!face.is_unknown && (
          <>
            <div className="face-dept">{face.department}</div>
            <div className="face-conf">{face.confidence}%</div>
          </>
        )}
      </div>
    </div>
  );
}
